export function resolveIcon(name: string): string | undefined {
  const key = name.toLowerCase().replace(/_/g, "-");
  const alias = FA_ALIASES[key];
  const codepoint = FA_ICONS[key] ?? (alias ? FA_ICONS[alias] : undefined);
  return codepoint;
}
